import{_ as a,c as s,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"段階 1：Bootstrap - 製品アイデアの構造化 | Agent App Factory チュートリアル","description":"Bootstrap段階が曖昧な製品アイデアを明確で構造化されたinput/idea.mdドキュメントに変換する方法を学びます。このチュートリアルではBootstrap Agentの責務、superpowers:brainstormスキルの使用方法、idea.mdの標準構造、品質チェックリストを解説します。","frontmatter":{"title":"段階 1：Bootstrap - 製品アイデアの構造化 | Agent App Factory チュートリアル","sidebarTitle":"製品アイデアの構造化","subtitle":"段階 1：Bootstrap - 製品アイデアの構造化","description":"Bootstrap段階が曖昧な製品アイデアを明確で構造化されたinput/idea.mdドキュメントに変換する方法を学びます。このチュートリアルではBootstrap Agentの責務、superpowers:brainstormスキルの使用方法、idea.mdの標準構造、品質チェックリストを解説します。","tags":["パイプライン","Bootstrap","製品アイデア"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"ja/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md","filePath":"ja/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"}'),e={name:"ja/hyz1992/agent-app-factory/advanced/stage-bootstrap/index.md"};function l(r,t,n,p,d,h){return o(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="段階-1-bootstrap-製品アイデアの構造化" tabindex="-1">段階 1：Bootstrap - 製品アイデアの構造化 <a class="header-anchor" href="#段階-1-bootstrap-製品アイデアの構造化" aria-label="Permalink to &quot;段階 1：Bootstrap - 製品アイデアの構造化&quot;">​</a></h1><p>BootstrapはAgent App Factoryパイプラインの最初の段階であり、あなたの曖昧な製品アイデアを整理して明確な<code>input/idea.md</code>ドキュメントにする役割を担います。これは後続のPRD、UI、Techなどすべての段階の起点であり、プロジェクト全体の方向性と品質を決定します。</p><h2 id="学習目標" tabindex="-1">学習目標 <a class="header-anchor" href="#学習目標" aria-label="Permalink to &quot;学習目標&quot;">​</a></h2><ul><li>曖昧な製品アイデアを標準テンプレートに従った<code>input/idea.md</code>ドキュメントに整理できる</li><li>Bootstrap Agentの責務境界（情報収集のみ、要件の創造はしない）を理解する</li><li>superpowers:brainstormスキルを使用して製品アイデアを深く掘り下げる方法を知る</li><li>どの情報をBootstrap段階に含めるべきか、含めるべきでないかを判断できる</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>製品アイデアはあるが、記述が曖昧かもしれません：</p><ul><li>&quot;フィットネスアプリを作りたい&quot;（漠然としすぎ）</li><li>&quot;REDのようなアプリを作りたい&quot;（差別化が不明）</li><li>&quot;ユーザーはより良いタスク管理ツールを必要としている&quot;（具体的な問題が不明）</li></ul><p>このような曖昧な記述は、後続の段階（PRD、UI、Tech）で明確な入力が不足し、最終的に生成されるアプリケーションがあなたの期待から完全に逸脱する原因となります。</p><h2 id="いつ使用すべきか" tabindex="-1">いつ使用すべきか <a class="header-anchor" href="#いつ使用すべきか" aria-label="Permalink to &quot;いつ使用すべきか&quot;">​</a></h2><p>パイプラインを開始する準備が整っており、以下の条件を満たしている場合：</p><ol><li><strong>初步的な製品アイデアがある</strong>（一文でも構いません）</li><li><strong>まだ要件書（PRD）を書いていない</strong>（PRDは後続の段階）</li><li><strong>技術スタックやUIスタイルを決定していない</strong>（これらは後続の段階）</li><li><strong>製品の範囲を制御し、オーバーデザインを回避したい</strong>（Bootstrap段階で非目標を明確にします）</li></ol><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>Bootstrap段階を開始する前に、以下を確認してください：</p><ul><li>✅ <a href="./../../start/init-project/">プロジェクト初期化</a>を完了している</li><li>✅ <a href="./../../start/pipeline-overview/">7段階パイプライン概要</a>を理解している</li><li>✅ AIアシスタント（Claude Code推奨）をインストール・設定済み</li><li>✅ 製品アイデアを準備済み（曖昧でも構いません）</li></ul></div><h2 id="コア概念" tabindex="-1">コア概念 <a class="header-anchor" href="#コア概念" aria-label="Permalink to &quot;コア概念&quot;">​</a></h2><h3 id="bootstrap段階とは" tabindex="-1">Bootstrap段階とは？ <a class="header-anchor" href="#bootstrap段階とは" aria-label="Permalink to &quot;Bootstrap段階とは？&quot;">​</a></h3><p><strong>Bootstrap</strong>はパイプライン全体の起点であり、その唯一の責務は<strong>断片的な製品アイデアを構造化されたドキュメントに整理すること</strong>です。</p><div class="info custom-block"><p class="custom-block-title">プロダクトマネージャーではない</p><p>Bootstrap Agentはプロダクトマネージャーではありません。要件や機能を代わりに作成・設計することはありません。その役割は：</p><ul><li>あなたが提供した情報を収集する</li><li>情報を整理・組織化する</li><li>標準テンプレートに従って提示する</li></ul><p>「どのような機能があるべきか」を決めるのではなく、「あなたが何を求めているか」を明確にする手助けをします。</p></div><h3 id="なぜ構造化が必要か" tabindex="-1">なぜ構造化が必要か？ <a class="header-anchor" href="#なぜ構造化が必要か" aria-label="Permalink to &quot;なぜ構造化が必要か？&quot;">​</a></h3><p>想像してください。シェフに「何か美味しいものを食べたい」と伝えるとします。</p><ul><li>❌ 曖昧な記述：シェフは推測するしかなく、あなたが全く食べたくない料理を作るかもしれません</li><li>✅ 構造化された記述：「辛くて香菜を使わない川料理が好きで、ご飯に合うものを希望」</li></ul><p>Bootstrap段階は「何か美味しいものを食べたい」を「辛くて香菜を使わない川料理」に変える作業です。</p><h3 id="出力ドキュメント構造" tabindex="-1">出力ドキュメント構造 <a class="header-anchor" href="#出力ドキュメント構造" aria-label="Permalink to &quot;出力ドキュメント構造&quot;">​</a></h3><p>Bootstrap段階は<code>input/idea.md</code>を生成し、以下のセクションを含みます：</p><table tabindex="0"><thead><tr><th>セクション</th><th>内容</th><th>例</th></tr></thead><tbody><tr><td><strong>要約</strong></td><td>製品を1-2文で概括</td><td>&quot;若者が日常の支出を素早く記録するためのモバイル家計簿アプリ&quot;</td></tr><tr><td><strong>問題 (Problem)</strong></td><td>ユーザーが直面するコアな課題</td><td>&quot;若者が月末に超支に気づくが、どこにお金を使ったか分からない&quot;</td></tr><tr><td><strong>ターゲットユーザー (Target User)</strong></td><td>具体的なユーザーペルソナ</td><td>&quot;18-30歳の社会人1〜3年目、技術能力は中程度&quot;</td></tr><tr><td><strong>コアバリュー (Core Value)</strong></td><td>なぜ価値があるか</td><td>&quot;3秒で記帳可能で、手動照会より80%の時間を節約&quot;</td></tr><tr><td><strong>仮説 (Assumptions)</strong></td><td>検証可能な2-4つの仮説</td><td>&quot;予算を管理できれば、ユーザーは2分かけてアプリを学習する意思がある&quot;</td></tr><tr><td><strong>非目標 (Non‑Goals)</strong></td><td>明確にしないこと</td><td>&quot;予算計画と財務アドバイスはしない&quot;</td></tr></tbody></table><h2 id="実践手順" tabindex="-1">実践手順 <a class="header-anchor" href="#実践手順" aria-label="Permalink to &quot;実践手順&quot;">​</a></h2><h3 id="ステップ1-製品アイデアの準備" tabindex="-1">ステップ1：製品アイデアの準備 <a class="header-anchor" href="#ステップ1-製品アイデアの準備" aria-label="Permalink to &quot;ステップ1：製品アイデアの準備&quot;">​</a></h3><p>パイプラインを開始する前に、製品アイデアをはっきりと考えます。完全な記述でも、単純なアイデアでも構いません。</p><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>フィットネス初心者がトレーニングを記録できるフィットネスアプリを作りたい。運動種類、時間、カロリーを記録し、今週の統計も確認できるようにしたい。</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">アイデアは荒くても構いません</p><p>一文でも構いません。Bootstrap Agentがsuperpowers:brainstormスキルを使って情報を補完します。</p></div><h3 id="ステップ2-bootstrap段階までパイプラインを起動" tabindex="-1">ステップ2：Bootstrap段階までパイプラインを起動 <a class="header-anchor" href="#ステップ2-bootstrap段階までパイプラインを起動" aria-label="Permalink to &quot;ステップ2：Bootstrap段階までパイプラインを起動&quot;">​</a></h3><p>Factoryプロジェクトディレクトリで実行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># パイプラインを起動（まだ起動していない場合）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># またはbootstrapから直接指定して起動</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span></code></pre></div><p>CLIが現在の状態と利用可能な段階を表示します。</p><h3 id="ステップ3-aiアシスタントがbootstrap-agentの定義を読み取る" tabindex="-1">ステップ3：AIアシスタントがBootstrap Agentの定義を読み取る <a class="header-anchor" href="#ステップ3-aiアシスタントがbootstrap-agentの定義を読み取る" aria-label="Permalink to &quot;ステップ3：AIアシスタントがBootstrap Agentの定義を読み取る&quot;">​</a></h3><p>AIアシスタント（Claude Codeなど）は自動的に<code>agents/bootstrap.agent.md</code>を読み取り、その責務と制約を理解します。</p><div class="info custom-block"><p class="custom-block-title">Agentの責務</p><p>Bootstrap Agentは以下のみ可能：</p><ul><li>会話でユーザーが提供した製品アイデアを読み取る</li><li><code>input/idea.md</code>に書き込む</li></ul><p>以下はできません：</p><ul><li>他のファイルを読み取る</li><li>他のディレクトリに書き込む</li><li>新しい要件を作成する</li></ul></div><h3 id="ステップ4-superpowers-brainstormスキルの強制使用" tabindex="-1">ステップ4：superpowers:brainstormスキルの強制使用 <a class="header-anchor" href="#ステップ4-superpowers-brainstormスキルの強制使用" aria-label="Permalink to &quot;ステップ4：superpowers:brainstormスキルの強制使用&quot;">​</a></h3><p>これはBootstrap段階の重要なステップです。AIアシスタントは情報がすでに十分完全だと思っていても、<strong>必ず</strong>先に<code>superpowers:brainstorm</code>スキルを呼び出す必要があります。</p><p><strong>brainstormスキルの役割</strong>：</p><ol><li><strong>問題の本質を深く掘り下げる</strong>：構造化された質問によって記述の盲点を発見する</li><li><strong>ターゲットユーザーペルソナを明確にする</strong>：「誰に売るのか」をはっきりさせる手助けをする</li><li><strong>コアバリューを検証する</strong>：競合との比較によって差別化を見つける</li><li><strong>暗黙の仮説を識別する</strong>：デフォルトで前提としているが未検証の仮説をリスト化する</li><li><strong>製品範囲を制御する</strong>：非目標を通じて境界を明確にする</li></ol><p><strong>AIアシスタントが行うこと</strong>：</p><ul><li><code>superpowers:brainstorm</code>スキルを呼び出す</li><li>あなたの元のアイデアを提供する</li><li>スキルで生成された質問であなたに質問する</li><li>回答を収集し、アイデアを洗練させる</li></ul><div class="danger custom-block"><p class="custom-block-title">このステップをスキップすると拒否されます</p><p>Sisyphusスケジューラーはbrainstormスキルが使用されたかを検証します。使用されていない場合、Bootstrap Agentが生成した産物は拒否され、再実行が必要になります。</p></div><h3 id="ステップ5-idea-mdの内容を確認" tabindex="-1">ステップ5：idea.mdの内容を確認 <a class="header-anchor" href="#ステップ5-idea-mdの内容を確認" aria-label="Permalink to &quot;ステップ5：idea.mdの内容を確認&quot;">​</a></h3><p>Bootstrap Agentが完了すると、<code>input/idea.md</code>が生成されます。よく確認する必要があります：</p><p><strong>チェックポイント ✅</strong>：</p><ol><li><p><strong>要約</strong>は明確か？</p><ul><li>✅ 含む：何をするか + 誰のためにか + 何を解決するか</li><li>❌ 漠然としすぎ：「効率を上げるツール」</li></ul></li><li><p><strong>問題の記述</strong>は具体的か？</p><ul><li>✅ 含む：シナリオ + 困難 + ネガティブな結果</li><li>❌ 空っぽ：「ユーザーエクスペリエンスが悪い」</li></ul></li><li><p><strong>ターゲットユーザー</strong>は明確か？</p><ul><li>✅ 具体的なペルソナがある（年齢/職業/技術能力）</li><li>❌ 漠然としている：「すべての人」</li></ul></li><li><p><strong>コアバリュー</strong>は定量化可能か？</p><ul><li>✅ 具体的な利点がある（80%の時間を節約）</li><li>❌ 空っぽ：「効率を向上」</li></ul></li><li><p><strong>仮説</strong>は検証可能か？</p><ul><li>✅ ユーザー調査で検証可能</li><li>❌ 主観的な判断：「ユーザーは気に入るはず」</li></ul></li><li><p><strong>非目標</strong>は十分か？</p><ul><li>✅ 少なくとも3つの機能をリストアップしない</li><li>❌ 欠落または少なすぎる</li></ul></li></ol><h3 id="ステップ6-継続、再試行、一時停止を選択" tabindex="-1">ステップ6：継続、再試行、一時停止を選択 <a class="header-anchor" href="#ステップ6-継続、再試行、一時停止を選択" aria-label="Permalink to &quot;ステップ6：継続、再試行、一時停止を選択&quot;">​</a></h3><p>確認後、CLIがオプションを表示します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">操作を選択してください：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] 継続（PRD段階に進む）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] 再試行（idea.mdを再生成）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] 一時停止（後で継続）</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">コードエディタで先に確認することを推奨</p><p>AIアシスタントで確認する前に、コードエディタで<code>input/idea.md</code>を開き、一字一句確認してください。一度PRD段階に入ると、修正コストが高くなります。</p></div><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="落とし穴1-アイデアの記述が曖昧すぎる" tabindex="-1">落とし穴1：アイデアの記述が曖昧すぎる <a class="header-anchor" href="#落とし穴1-アイデアの記述が曖昧すぎる" aria-label="Permalink to &quot;落とし穴1：アイデアの記述が曖昧すぎる&quot;">​</a></h3><p><strong>間違った例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>フィットネスアプリを作りたい</span></span></code></pre></div><p><strong>結果</strong>：Bootstrap Agentはbrainstormスキルを使って多くの質問をし、情報を補完します。</p><p><strong>推奨</strong>：最初から明確に記述する：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>フィットネス初心者がトレーニングを記録できるモバイルフィットネスアプリを作りたい。運動種類、時間、カロリーを記録し、今週の統計も確認できるようにしたい。</span></span></code></pre></div><h3 id="落とし穴2-技術実装の詳細を含める" tabindex="-1">落とし穴2：技術実装の詳細を含める <a class="header-anchor" href="#落とし穴2-技術実装の詳細を含める" aria-label="Permalink to &quot;落とし穴2：技術実装の詳細を含める&quot;">​</a></h3><p><strong>間違った例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>React Nativeで構築したい。バックエンドはExpress、データベースはPrisma...</span></span></code></pre></div><p><strong>結果</strong>：Bootstrap Agentはこれらの内容を拒否します（製品アイデアのみ収集し、技術スタックはTech段階で決定されます）。</p><p><strong>推奨</strong>：「何をするか」のみ記述し、「どのようにするか」は記述しない。</p><h3 id="落とし穴3-ターゲットユーザーの記述が曖昧すぎる" tabindex="-1">落とし穴3：ターゲットユーザーの記述が曖昧すぎる <a class="header-anchor" href="#落とし穴3-ターゲットユーザーの記述が曖昧すぎる" aria-label="Permalink to &quot;落とし穴3：ターゲットユーザーの記述が曖昧すぎる&quot;">​</a></h3><p><strong>間違った例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>フィットネスを必要とするすべての人</span></span></code></pre></div><p><strong>結果</strong>：後続の段階で設計方向を明確にできません。</p><p><strong>推奨</strong>：ペルソナを明確にする：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18-30歳のフィットネス初心者、体系的なトレーニングを始めたばかり、技術能力は中程度、簡易な記録と統計確認を希望。</span></span></code></pre></div><h3 id="落とし穴4-非目標が欠落または少なすぎる" tabindex="-1">落とし穴4：非目標が欠落または少なすぎる <a class="header-anchor" href="#落とし穴4-非目標が欠落または少なすぎる" aria-label="Permalink to &quot;落とし穴4：非目標が欠落または少なすぎる&quot;">​</a></h3><p><strong>間違った例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目標：なし</span></span></code></pre></div><p><strong>結果</strong>：後続のPRDとCode段階でオーバーデザインが発生し、技術的な複雑度が増加する可能性があります。</p><p><strong>推奨</strong>：少なくとも3つリストアップ：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>非目標：</span></span>
<span class="line"><span>- チーム協働とソーシャル機能（MVPは個人にフォーカス）</span></span>
<span class="line"><span>- 複雑なデータ分析とレポート</span></span>
<span class="line"><span>- サードパーティのフィットネス機器との連携</span></span></code></pre></div><h3 id="落とし穴5-仮説が検証不可能" tabindex="-1">落とし穴5：仮説が検証不可能 <a class="header-anchor" href="#落とし穴5-仮説が検証不可能" aria-label="Permalink to &quot;落とし穴5：仮説が検証不可能&quot;">​</a></h3><p><strong>間違った例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>仮説：ユーザーは私たちのデザインを気に入るはず</span></span></code></pre></div><p><strong>結果</strong>：ユーザー調査で検証できず、MVPが失敗する可能性があります。</p><p><strong>推奨</strong>：検証可能な仮説を書く：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>仮説：トレーニングを体系的に記録できれば、ユーザーは5分かけてアプリを学習する意思がある。</span></span></code></pre></div><h2 id="本レッスンのまとめ" tabindex="-1">本レッスンのまとめ <a class="header-anchor" href="#本レッスンのまとめ" aria-label="Permalink to &quot;本レッスンのまとめ&quot;">​</a></h2><p>Bootstrap段階の核心は<strong>構造化</strong>です：</p><ol><li><strong>入力</strong>：あなたの曖昧な製品アイデア</li><li><strong>プロセス</strong>：AIアシスタントがsuperpowers:brainstormスキルを使って深く掘り下げる</li><li><strong>出力</strong>：標準テンプレートに従った<code>input/idea.md</code></li><li><strong>検証</strong>：記述が具体的か、ユーザーが明確か、価値が定量化可能かをチェック</li></ol><div class="tip custom-block"><p class="custom-block-title">重要な原則</p><ul><li>❌ しないこと：要件を作成しない、機能を設計しない、技術スタックを決定しない</li><li>✅ すること：情報を収集する、整理・組織化する、テンプレートに従って提示する</li></ul></div><h2 id="次回レッスンの予告" tabindex="-1">次回レッスンの予告 <a class="header-anchor" href="#次回レッスンの予告" aria-label="Permalink to &quot;次回レッスンの予告&quot;">​</a></h2><blockquote><p>次回レッスンでは <strong><a href="./../stage-prd/">段階 2：PRD - 製品要件書の生成</a></strong> を学びます。</p><p>学習内容：</p><ul><li>idea.mdをMVPレベルのPRDに変換する方法</li><li>PRDに含まれる内容（ユーザーストーリー、機能リスト、非機能要件）</li><li>MVP範囲と優先順位を明確にする方法</li><li>PRDに技術的な詳細を含めてはいけない理由</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Bootstrap Agent 定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/bootstrap.agent.md" target="_blank" rel="noreferrer"><code>agents/bootstrap.agent.md</code></a></td><td>1-93</td></tr><tr><td>Bootstrap Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/bootstrap/skill.md" target="_blank" rel="noreferrer"><code>skills/bootstrap/skill.md</code></a></td><td>1-433</td></tr><tr><td>パイプライン定義（Bootstrap段階）</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>8-18</td></tr><tr><td>スケジューラー定義</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>重要な制約</strong>：</p><ul><li><strong>brainstormスキルの強制使用</strong>：bootstrap.agent.md:70-71</li><li><strong>技術詳細の禁止</strong>：bootstrap.agent.md:47</li><li><strong>複数のアイデアの統合禁止</strong>：bootstrap.agent.md:48</li><li><strong>出力ファイルは必ずinput/idea.mdに保存</strong>：bootstrap.agent.md:50</li></ul><p><strong>終了条件</strong>（pipeline.yaml:15-18）：</p><ul><li>idea.mdが存在する</li><li>idea.mdが一貫性のある製品アイデアを記述している</li><li>Agentが<code>superpowers:brainstorm</code>スキルを使用して深く掘り下げている</li></ul><p><strong>Skillの内容フレームワーク</strong>：</p><ul><li><strong>思考フレームワーク</strong>：抽出 vs 創造、問題優先、具体化、仮説検証</li><li><strong>質問テンプレート</strong>：問題、ターゲットユーザー、コアバリュー、MVP仮説、非目標について</li><li><strong>情報抽出テクニック</strong>：機能から問題を逆推測、文句から要件を抽出、暗黙の仮説を識別</li><li><strong>品質チェックリスト</strong>：完全性、具体性、整合性、禁止項目</li><li><strong>意思決定原則</strong>：質問を優先、問題志向、具体が抽象より優先、検証可能性、範囲制御</li><li><strong>よくあるシナリオ処理</strong>：ユーザーが一文のみ提供、多くの機能を記述、競合を記述、矛盾するアイデア</li><li><strong>例の比較</strong>：悪いidea.md vs 良いidea.md</li></ul></details>`,91)])])}const u=a(e,[["render",l]]);export{g as __pageData,u as default};
